import{_ as a,o as t,c as l,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"20. Casual Employment","description":"","frontmatter":{"title":"20. Casual Employment","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","employment","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/employment/20-casual-employment.md","filePath":"ebas/allied-health/employment/20-casual-employment.md"}'),r={name:"ebas/allied-health/employment/20-casual-employment.md"};function n(s,e,i,p,m,h){return t(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="_20-casual-employment" tabindex="-1">20. Casual Employment <a class="header-anchor" href="#_20-casual-employment" aria-label="Permalink to &quot;20. Casual Employment&quot;">​</a></h1><p><strong>20.1</strong> A casual Employee is one who is engaged in relieving work or work of a casual nature and whose engagement is terminable by the Employer in accordance with the Employer&#39;s requirements, without the requirement of prior notice by either the Employer or the Employee, but does not include an Employee who could properly be classified under <a href="/eba/ebas/allied-health/employment/18-full-time-employment.html">clause 18</a> - Full-time employment, <a href="/eba/ebas/allied-health/employment/19-part-time-employment.html">clause 19</a> - Part-time employment or <a href="/eba/ebas/allied-health/employment/22-fixed-term-employment.html">clause 22</a> - Fixed term employment.</p><p><strong>20.2</strong> Conversion to permanent employment</p><p><strong>(a)</strong> Where an Employee has been engaged as a casual Employee but is not engaged in relieving work or work of a casual nature, where requested by the Employee, the Employer will convert the Employee to part time or full time employment (whichever is applicable), and the Employee’s period of service as a casual Employee counts as part time or full time service for the purpose of:</p><p><strong>(i)</strong> transfer of business under <a href="/eba/ebas/allied-health/preliminary/11-transfer-of-business.html">clause 11</a>;</p><p><strong>(ii)</strong> termination of employment under <a href="/eba/ebas/allied-health/employment/24-termination-of-employment.html">clause 24</a> (see subclause 24.2);</p><p><strong>(iii)</strong> calculating a severance payment upon redundancy under <a href="/eba/ebas/allied-health/employment/25-redundancy-and-related-entitlements.html">clause 25</a>;</p><p><strong>(iv)</strong> the rate of personal leave accrual at subclause 62.1 save that the Employer is not required to credit the Employee with leave for the period they were engaged as a casual;</p><p><strong>(v)</strong> parental leave under <a href="/eba/ebas/allied-health/leave/70-parental-leave.html">clause 70</a>;</p><p><strong>(vi)</strong> long service leave under <a href="/eba/ebas/allied-health/leave/72-long-service-leave.html">clause 72</a>; and</p><p><strong>(vii)</strong> eligibility to request flexible working arrangements under <a href="/eba/ebas/allied-health/workplace-rights/96-flexible-working-arrangements.html">clause 96</a>.</p><p><strong>(b)</strong> Where there is a dispute about:</p><p><strong>(i)</strong> whether the Employee is engaged in relieving work or work of a casual nature or not; and/or</p><p><strong>(ii)</strong> when the Employee ceased to be engaged in relieving work or work of a casual nature; the Dispute Resolution Procedure at <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> will be utilised.</p><p><strong>20.3</strong> Minimum engagement The minimum period of engagement of a casual Employee is three (3) hours per ordinary shift.</p><p><strong>20.4</strong> Payments A casual Employee will be paid for all work, other than for overtime (see subclause 52.7 for casual overtime provisions), performed on a:</p><p><strong>(a)</strong> weekday an amount equal to 1/38th of the weekly wage appropriate to the Employee&#39;s classification per hour plus 25%;</p><p><strong>(b)</strong> Saturday or Sunday an amount equal to 1/38th of the weekly wage appropriate to the Employee&#39;s classification per hour plus 75%; and</p><p><strong>(c)</strong> public holiday an amount equal to 1/38th of the weekly wage appropriate to the Employee&#39;s classification per hour plus 175%.</p><p><strong>20.5</strong> In addition a casual Employee will be entitled to receive the appropriate uniform and other allowances contained in this Agreement.</p><p><strong>20.6</strong> The provisions of <a href="/eba/ebas/allied-health/employment/24-termination-of-employment.html">clause 24</a> (Termination of Employment), <a href="/eba/ebas/allied-health/leave/59-annual-leave.html">clause 59</a> (Annual Leave), and <a href="/eba/ebas/allied-health/leave/62-personal-leave-including-carer-s-leave.html">clause 62</a> (Personal/Carer’s Leave) except in so far as it expressly applies to casual Employees, will not apply in the case of a casual Employee.</p><p><strong>20.7</strong> The list in subclause 20.4 is not intended to be exhaustive and relevant clauses should be referred to in order to determine any casual entitlement.</p><p>Plain language terms: casual.</p>',23)])])}const d=a(r,[["render",n]]);export{c as __pageData,d as default};
